669 /// Return the scalar or shorter vector formed by the non-empty defined prefix
670 /// of
671 /// \p C if the remaining lanes are all undef/poison.
672 static Constant *getDefinedPrefix(Constant *C, FixedVectorType *VTy) {
673   unsigned NumElts = VTy->getNumElements();
674   SmallVector<Constant *, 8> PrefixElts;
675   PrefixElts.reserve(NumElts);
676   bool SawUndef = false;
677 
678   for (unsigned I = 0; I != NumElts; ++I) {
679     Constant *Elt = C->getAggregateElement(I);
680     if (!Elt)
681       return nullptr;
682 
683     if (isa<UndefValue>(Elt)) {
684       SawUndef = true;
685       continue;
686     }
687 
688     if (SawUndef)
689       return nullptr;
690 
691     PrefixElts.push_back(Elt);
692   }
693 
694   if (!SawUndef || PrefixElts.empty())
695     return nullptr;
696 
697   if (PrefixElts.size() == 1)
698     return PrefixElts.front();
699 
700   return ConstantVector::get(PrefixElts);
701 }
