1671 /// Try to transform:
1672 ///   if () { *P = v1; } else { *P = v2 }
1673 /// or:
1674 ///   *P = v1; if () { *P = v2; }
1675 /// into a phi node with a store in the successor.
1676 bool InstCombinerImpl::mergeStoreIntoSuccessor(StoreInst &SI) {
1677   if (!SI.isUnordered())
1678     return false; // This code has not been audited for volatile/ordered case.
1679 
1680   // Check if the successor block has exactly 2 incoming edges.
1681   BasicBlock *StoreBB = SI.getParent();
1682   BasicBlock *DestBB = StoreBB->getTerminator()->getSuccessor(0);
1683   if (!DestBB->hasNPredecessors(2))
1684     return false;
1685 
1686   // Capture the other block (the block that doesn't contain our store).
1687   pred_iterator PredIter = pred_begin(DestBB);
1688   if (*PredIter == StoreBB)
1689     ++PredIter;
1690   BasicBlock *OtherBB = *PredIter;
1691 
1692   // Bail out if all of the relevant blocks aren't distinct. This can happen,
1693   // for example, if SI is in an infinite loop.
1694   if (StoreBB == DestBB || OtherBB == DestBB)
1695     return false;
1696 
1697   // Verify that the other block is not empty apart from the terminator.
1698   BasicBlock::iterator BBI(OtherBB->getTerminator());
1699   if (BBI == OtherBB->begin())
1700     return false;
1701 
1702   auto OtherStoreIsMergeable = [&](StoreInst *OtherStore) -> bool {
1703     if (!OtherStore ||
1704         OtherStore->getPointerOperand() != SI.getPointerOperand())
1705       return false;
1706 
1707     auto *SIVTy = SI.getValueOperand()->getType();
1708     auto *OSVTy = OtherStore->getValueOperand()->getType();
1709     return CastInst::isBitOrNoopPointerCastable(OSVTy, SIVTy, DL) &&
1710            SI.hasSameSpecialState(OtherStore);
1711   };
1712 
1713   // If the other block ends in an unconditional branch, check for the 'if then
1714   // else' case. There is an instruction before the branch.
1715   StoreInst *OtherStore = nullptr;
1716   if (isa<UncondBrInst>(BBI)) {
1717     --BBI;
1718     // Skip over debugging info and pseudo probes.
1719     while (BBI->isDebugOrPseudoInst()) {
1720       if (BBI==OtherBB->begin())
1721         return false;
1722       --BBI;
1723     }
1724     // If this isn't a store, isn't a store to the same location, or is not the
1725     // right kind of store, bail out.
1726     OtherStore = dyn_cast<StoreInst>(BBI);
1727     if (!OtherStoreIsMergeable(OtherStore))
1728       return false;
1729   } else if (auto *OtherBr = dyn_cast<CondBrInst>(BBI)) {
