1348     // x86_amx type happy.
1349     if (V->getType()->isX86_AMXTy())
1350       return false;
1351     if (!SI.isAtomic() || isSupportedAtomicType(V->getType())) {
1352       combineStoreToNewValue(IC, SI, V);
1353       return true;
1354     }
1355   }
1356 
1357   if (Value *U = likeBitCastFromVector(IC, V))
1358     if (!SI.isAtomic() || isSupportedAtomicType(U->getType())) {
1359       combineStoreToNewValue(IC, SI, U);
1360       return true;
1361     }
1362 
1363   // FIXME: We should also canonicalize stores of vectors when their elements
1364   // are cast to other types.
1365   return false;
1366 }
