1368 static bool unpackStoreToAggregate(InstCombinerImpl &IC, StoreInst &SI) {
1369   // FIXME: We could probably with some care handle both volatile and atomic
1370   // stores here but it isn't clear that this is important.
1371   if (!SI.isSimple())
1372     return false;
1373 
1374   Value *V = SI.getValueOperand();
1375   Type *T = V->getType();
1376 
1377   if (!T->isAggregateType())
1378     return false;
1379 
1380   if (auto *ST = dyn_cast<StructType>(T)) {
1381     // If the struct only have one element, we unpack.
1382     unsigned Count = ST->getNumElements();
1383     if (Count == 1) {
1384       V = IC.Builder.CreateExtractValue(V, 0);
1385       combineStoreToNewValue(IC, SI, V);
1386       return true;
1387     }
1388 
1389     // We don't want to break loads with padding here as we'd loose
1390     // the knowledge that padding exists for the rest of the pipeline.
1391     const DataLayout &DL = IC.getDataLayout();
1392     auto *SL = DL.getStructLayout(ST);
1393 
1394     if (SL->hasPadding())
1395       return false;
1396 
1397     const auto Align = SI.getAlign();
1398 
1399     SmallString<16> EltName = V->getName();
1400     EltName += ".elt";
1401     auto *Addr = SI.getPointerOperand();
1402     SmallString<16> AddrName = Addr->getName();
1403     AddrName += ".repack";
1404 
1405     auto *IdxType = DL.getIndexType(Addr->getType());
1406     for (unsigned i = 0; i < Count; i++) {
1407       auto *Ptr = IC.Builder.CreateInBoundsPtrAdd(
1408           Addr, IC.Builder.CreateTypeSize(IdxType, SL->getElementOffset(i)),
1409           AddrName);
1410       auto *Val = IC.Builder.CreateExtractValue(V, i, EltName);
1411       auto EltAlign =
1412           commonAlignment(Align, SL->getElementOffset(i).getKnownMinValue());
1413       llvm::Instruction *NS = IC.Builder.CreateAlignedStore(Val, Ptr, EltAlign);
1414       NS->setAAMetadata(SI.getAAMetadata());
1415     }
1416 
1417     return true;
1418   }
1419 
1420   if (auto *AT = dyn_cast<ArrayType>(T)) {
1421     // If the array only have one element, we unpack.
1422     auto NumElements = AT->getNumElements();
1423     if (NumElements == 1) {
1424       V = IC.Builder.CreateExtractValue(V, 0);
1425       combineStoreToNewValue(IC, SI, V);
1426       return true;
1427     }
1428 
1429     // Bail out if the array is too large. Ideally we would like to optimize
1430     // arrays of arbitrary size but this has a terrible impact on compile time.
1431     // The threshold here is chosen arbitrarily, maybe needs a little bit of
1432     // tuning.
1433     if (NumElements > IC.MaxArraySizeForCombine)
1434       return false;
1435 
1436     const DataLayout &DL = IC.getDataLayout();
1437     TypeSize EltSize = DL.getTypeAllocSize(AT->getElementType());
1438     const auto Align = SI.getAlign();
1439 
1440     SmallString<16> EltName = V->getName();
1441     EltName += ".elt";
1442     auto *Addr = SI.getPointerOperand();
1443     SmallString<16> AddrName = Addr->getName();
1444     AddrName += ".repack";
1445 
1446     auto *IdxType = Type::getInt64Ty(T->getContext());
1447     auto *Zero = ConstantInt::get(IdxType, 0);
1448 
1449     TypeSize Offset = TypeSize::getZero();
1450     for (uint64_t i = 0; i < NumElements; i++) {
1451       Value *Indices[2] = {
1452         Zero,
1453         ConstantInt::get(IdxType, i),
1454       };
1455       auto *Ptr =
1456           IC.Builder.CreateInBoundsGEP(AT, Addr, ArrayRef(Indices), AddrName);
1457       auto *Val = IC.Builder.CreateExtractValue(V, i, EltName);
1458       auto EltAlign = commonAlignment(Align, Offset.getKnownMinValue());
1459       Instruction *NS = IC.Builder.CreateAlignedStore(Val, Ptr, EltAlign);
1460       NS->setAAMetadata(SI.getAAMetadata());
1461       Offset += EltSize;
1462     }
1463 
1464     return true;
1465   }
1466 
1467   return false;
1468 }
