1470 /// equivalentAddressValues - Test if A and B will obviously have the same
1471 /// value. This includes recognizing that %t0 and %t1 will have the same
1472 /// value in code like this:
1473 ///   %t0 = getelementptr \@a, 0, 3
1474 ///   store i32 0, i32* %t0
1475 ///   %t1 = getelementptr \@a, 0, 3
1476 ///   %t2 = load i32* %t1
1477 ///
1478 static bool equivalentAddressValues(Value *A, Value *B) {
1479   // Test if the values are trivially equivalent.
1480   if (A == B) return true;
1481 
1482   // Test if the values come form identical arithmetic instructions.
1483   // This uses isIdenticalToWhenDefined instead of isIdenticalTo because
1484   // its only used to compare two uses within the same basic block, which
1485   // means that they'll always either have the same value or one of them
1486   // will have an undefined value.
1487   if (isa<BinaryOperator>(A) ||
1488       isa<CastInst>(A) ||
1489       isa<PHINode>(A) ||
1490       isa<GetElementPtrInst>(A))
1491     if (Instruction *BI = dyn_cast<Instruction>(B))
1492       if (cast<Instruction>(A)->isIdenticalToWhenDefined(BI))
1493         return true;
1494 
1495   // Otherwise they may not be equivalent.
1496   return false;
1497 }
