703 /// Combine loads to match the type of their uses' value after looking
704 /// through intervening bitcasts.
705 ///
706 /// The core idea here is that if the result of a load is used in an operation,
707 /// we should load the type most conducive to that operation. For example, when
708 /// loading an integer and converting that immediately to a pointer, we should
709 /// instead directly load a pointer.
710 ///
711 /// However, this routine must never change the width of a load or the number of
712 /// loads as that would introduce a semantic change. This combine is expected to
713 /// be a semantic no-op which just allows loads to more closely model the types
714 /// of their consuming operations.
715 ///
716 /// Currently, we also refuse to change the precise type used for an atomic load
717 /// or a volatile load. This is debatable, and might be reasonable to change
718 /// later. However, it is risky in case some backend or other part of LLVM is
719 /// relying on the exact type loaded to select appropriate atomic operations.
720 static Instruction *combineLoadToOperationType(InstCombinerImpl &IC,
721                                                LoadInst &Load) {
722   // FIXME: We could probably with some care handle both volatile and ordered
723   // atomic loads here but it isn't clear that this is important.
724   if (!Load.isUnordered())
725     return nullptr;
726 
727   if (Load.use_empty())
728     return nullptr;
729 
730   // swifterror values can't be bitcasted.
731   if (Load.getPointerOperand()->isSwiftError())
732     return nullptr;
733 
734   // Fold away bit casts of the loaded value by loading the desired type.
